// ─── Text Chunking Node ───────────────────────────────────────────
// Splits document content into overlapping chunks for better retrieval.
// Each chunk becomes one vector in the database.

const items = $input.all();
const CHUNK_SIZE = 500;      // characters per chunk
const OVERLAP    = 80;       // character overlap between consecutive chunks

const chunks = [];

for (const item of items) {
  const fileName = item.json.fileName ?? item.json.name ?? 'unknown';
  const rawText  = item.json.data
    ? Buffer.from(item.json.data, 'base64').toString('utf-8')
    : (item.json.text ?? item.json.content ?? '');

  // Strip extra whitespace and normalize line breaks
  const text = rawText.replace(/\r\n/g, '\n').replace(/\s{3,}/g, ' ').trim();

  if (!text) continue;

  let start = 0;
  let chunkIndex = 0;

  while (start < text.length) {
    const end      = Math.min(start + CHUNK_SIZE, text.length);
    const chunkText = text.slice(start, end).trim();

    if (chunkText.length > 20) {
      chunks.push({
        json: {
          chunkId   : `${fileName}__chunk_${chunkIndex}`,
          fileName,
          chunkIndex,
          text      : chunkText,
        },
      });
      chunkIndex++;
    }

    start += CHUNK_SIZE - OVERLAP;
  }
}

return chunks;

// ─── Build Pinecone Vector Object ─────────────────────────────────
// Merges the Gemini embedding with chunk metadata
// into the exact JSON structure Pinecone's upsert endpoint expects.
// NOTE: Gemini text-embedding-004 returns 768-dimensional vectors.

const embedding = $json.embedding?.values;

if (!Array.isArray(embedding) || embedding.length === 0) {
  throw new Error('No embedding returned by Gemini for chunk: ' + $('Extract & Chunk Text').item.json.chunkId);
}

return [
  {
    json: {
      vectors: [
        {
          id      : $('Extract & Chunk Text').item.json.chunkId,
          values  : embedding,
          metadata: {
            text      : $('Extract & Chunk Text').item.json.text,
            fileName  : $('Extract & Chunk Text').item.json.fileName,
            chunkIndex: $('Extract & Chunk Text').item.json.chunkIndex,
          },
        },
      ],
      namespace: 'knowledge-base',
    },
  },
];
